const PAIRS = {
  EUR: 'EUR/USD',
  CAD: 'CAD/USD',
  GBP: 'GBP/USD',
  MXN: 'MXN/USD',
  ARS: 'ARS/USD',
  CLP: 'CLP/USD',
  BRL: 'BRL/USD',
  COP: 'COP/USD',
};

function flatNode(name) {
  return $(name)
    .all()
    .flatMap((item) => {
      const j = item.json;
      return Array.isArray(j) ? j : [j];
    });
}

const blended = flatNode('Frankfurter USD rates');
const banrep = flatNode('Frankfurter COP (Banrep)');

if (!blended.length && !banrep.length) {
  throw new Error('Frankfurter no devolvió datos');
}

const byQuote = {};
for (const row of blended) {
  if (!row?.quote || row.rate == null || row.quote === 'COP') continue;
  if (!byQuote[row.quote]) byQuote[row.quote] = [];
  byQuote[row.quote].push(row);
}

const copRows = banrep.filter((r) => r?.quote === 'COP' && r.rate != null);
if (copRows.length) byQuote.COP = copRows;

const fetchedAt = new Date().toISOString();
const out = [];

for (const [quote, series] of Object.entries(byQuote)) {
  series.sort((a, b) => a.date.localeCompare(b.date));
  const latest = series[series.length - 1];
  const rates = series.map((s) => Number(s.rate));
  const h = Math.max(...rates);
  const c = Number(latest.rate);

  out.push({
    json: {
      base: 'USD',
      par: PAIRS[quote] || `${quote}/USD`,
      quote_currency: quote,
      c,
      h,
      rate: c,
      rate_date: latest.date,
      source: 'frankfurter',
      provider: quote === 'COP' ? 'banrep' : 'blended',
      fetched_at: fetchedAt,
    },
  });
}

if (!out.length) {
  throw new Error('No se pudo normalizar ningún par de Frankfurter');
}

return out;

const baseUrl = ($env.SUPABASE_URL || '').replace(/\/$/, '');
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY || '';

if (!baseUrl || !serviceKey) {
  throw new Error(
    'Faltan SUPABASE_URL o SUPABASE_SERVICE_ROLE_KEY en n8n ($env; npm run n8n:moni)',
  );
}

const upsertUrl = `${baseUrl}/rest/v1/daily_rates?on_conflict=rate_date,quote_currency`;
const headers = {
  apikey: serviceKey,
  Authorization: `Bearer ${serviceKey}`,
  'Content-Type': 'application/json',
  'Content-Profile': 'moni_exchange',
  Prefer: 'resolution=merge-duplicates,return=representation',
};

const saved = [];

for (const item of $input.all()) {
  const j = item.json;
  const row = {
    rate_date: j.rate_date,
    base_currency: 'USD',
    quote_currency: j.quote_currency,
    par: j.par,
    c: j.c,
    h: j.h,
    rate: j.rate,
    source: j.source || 'frankfurter',
    provider: j.provider || 'blended',
    fetched_at: j.fetched_at,
  };

  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: upsertUrl,
    headers,
    body: row,
    json: true,
  });

  saved.push({ json: { ...row, supabase: res } });
}

return saved;
